object ArgumentValidator {

  // Characters that must never appear in any argument (shell metacharacters)
  private val dangerousPatterns = List(
    """;""", """&""", """|""", """`""", """$""", """(""", """)""",
    """\n""", """\r""", """>>""", """<<""", """>""", """<"""
  )

  def validateArgument(command: String, arg: String): Either[String, String] = {
    // Check for dangerous characters first
    if (containsDangerousCharacters(arg)) {
      Left(s"Argument contains forbidden characters: '$arg'")
    } else if (arg.contains("\u0000")) {
      Left(s"Argument contains null byte: '$arg'")
    } else if (arg.length > 256) {
      Left(s"Argument too long (max 256 chars): '${arg.take(20)}...'")
    } else {
      val patterns = CommandWhitelist.getArgumentPatterns(command)
      if (patterns.isEmpty && arg.isEmpty) {
        Right(arg)
      } else if (patterns.isEmpty) {
        Left(s"Command '$command' does not accept arguments")
      } else if (patterns.exists(pattern => arg.matches(pattern))) {
        Right(arg)
      } else {
        Left(s"Argument '$arg' does not match any allowed pattern for command '$command'")
      }
    }
  }

  private def containsDangerousCharacters(input: String): Boolean = {
    dangerousPatterns.exists(input.contains)
  }

  def validateAllArguments(command: String, args: List[String]): Either[List[String], List[String]] = {
    val results = args.map(arg => validateArgument(command, arg))
    val errors = results.collect { case Left(err) => err }
    if (errors.nonEmpty) Left(errors)
    else Right(results.collect { case Right(validArg) => validArg })
  }
}

class CommandExecutionService {

  private val maxArguments = 20

  def execute(request: CommandRequest): Either[String, CommandResult] = {
    for {
      executablePath <- CommandWhitelist.resolveCommand(request.command)
        .toRight(s"Command '${request.command}' is not in the whitelist of allowed commands")
      _ <- validateArgumentCount(request.arguments)
      validatedArgs <- ArgumentValidator.validateAllArguments(request.command, request.arguments)
        .left.map(errors => s"Argument validation failed: ${errors.mkString("; ")}")
      result <- runCommand(executablePath, validatedArgs)
    } yield result
  }

  private def validateArgumentCount(args: List[String]): Either[String, Unit] = {
    if (args.length > maxArguments)
      Left(s"Too many arguments (max $maxArguments, got ${args.length})")
    else
      Right(())
  }

  private def runCommand(executablePath: String, args: List[String]): Either[String, CommandResult] = {
    Try {
      val stdoutBuilder = new StringBuilder
      val stderrBuilder = new StringBuilder

      val processLogger = ProcessLogger(
        line => stdoutBuilder.append(line).append("\n"),
        line => stderrBuilder.append(line).append("\n")
      )

      // Build command as a sequence - this avoids shell interpretation entirely.
      // Process(Seq(...)) passes arguments directly to execve() without any shell.
      val commandSeq: Seq[String] = executablePath +: args
      val exitCode = Process(commandSeq).!(processLogger)

      CommandResult(
        exitCode = exitCode,
        stdout = stdoutBuilder.toString().trim,
        stderr = stderrBuilder.toString().trim,
        success = exitCode == 0
      )
    } match {
      case Success(result) => Right(result)
      case Failure(ex) => Left(s"Command execution failed: ${ex.getMessage}")
    }
  }
}

